// === Карта выдачи: slug → способ доставки ===
// Каталог «Делай Дело», 18 продуктов = 16 файлов (Drive) + 2 Pro‑тарифа (link).
// При появлении нового продукта — добавь строку в MAP, обнови CATALOG в delaydelo-create-payment.
//
// deliveryType:
//   'file' — n8n скачает файл из Google Drive и приложит к письму (PDF/Excel/zip).
//   'link' — n8n отправит письмо со ссылкой без вложения (Pro‑доступ к калькулятору).
const MAP = {
  // Маркетплейсы
  'unit-economy-excel':      { deliveryType: 'file', fileId: '1sTWnDW7546HeegTkUjho6joDxC4rYDqQ', fileName: 'unit-economy-excel.zip', title: 'Юнит‑экономика SKU для WB и Ozon' },
  'wbozon-zero-to-100k':     { deliveryType: 'file', fileId: '1ObFrfPgFCzCYSyc5VKjVciPoP7I5sXwZ', fileName: 'wbozon-zero-to-100k.pdf', title: 'Core‑гайд: WB и Ozon с нуля до 100 000 ₽ оборота' },
  'wb-ozon-card-seo':        { deliveryType: 'file', fileId: '1IJK4FiSTGeh05feQuQqzwzOkBbo6bjmQ', fileName: 'wb-ozon-card-seo.zip', title: 'SEO карточек WB и Ozon: ключи, заголовки, описания' },
  'wb-ozon-reviews':         { deliveryType: 'file', fileId: '1Fk8_jO2J27611bRCQv2llRxA8h_rfPtV', fileName: 'wb-ozon-reviews.zip', title: 'Управление отзывами WB и Ozon' },
  'wb-card-prompts':         { deliveryType: 'file', fileId: '1ypbEryr4VVOdm1SSoml6H_NJf_ERvJN9', fileName: 'wb-card-prompts.pdf', title: 'Промпт‑пак: AI‑описания карточек WB и Ozon' },
  'china-suppliers':         { deliveryType: 'file', fileId: '1oJSW-f98Atkonwm7hiD04WQETwAlUVXZ', fileName: 'china-suppliers.pdf', title: 'Поставщики из Китая для WB и Ozon' },
  'wb-internal-ads':         { deliveryType: 'file', fileId: '1WV4PZ1Drfd6USWlSDoqPalTAy8uDfi-P', fileName: 'wb-internal-ads.pdf', title: 'Внутренняя реклама WB' },
  'ozon-after-wb':           { deliveryType: 'file', fileId: '1ZIrqAmhez0Xdcu2xh4tkERcaaEcgg2Ei', fileName: 'ozon-after-wb.pdf', title: 'Выход на Ozon после WB' },
  'yandex-market-launch':    { deliveryType: 'file', fileId: '1uAPYBSqGL00oWd2CjOmsBcIOlJa1rqci', fileName: 'yandex-market-launch.pdf', title: 'Запуск на Яндекс.Маркете' },
  // Самозанятые / ИП
  'self-employed-coreguide': { deliveryType: 'file', fileId: '1gPYI9I-KnS4MXMhuDNctykyAc2m14qa0', fileName: 'self-employed-coreguide.pdf', title: 'Core‑гайд самозанятого: запуск и первые 10 клиентов' },
  'self-employed-finance':   { deliveryType: 'file', fileId: '19npizAKH_KOXvm2dTXiQF5V3Ddpxm1GH', fileName: 'self-employed-finance.zip', title: 'Финансовый учёт самозанятого' },
  'services-marketplaces':   { deliveryType: 'file', fileId: '1b9kDzboHGHha-uKCx8iIGoIKVUZFQ_aH', fileName: 'services-marketplaces.pdf', title: 'Маркетплейсы услуг: Avito, Profi.ru, YouDo, Я.Услуги' },
  'raise-price-scripts':     { deliveryType: 'file', fileId: '1Zc6rzb1y6IDdTmbaBKBTPF04A9hPLqVS', fileName: 'raise-price-scripts.pdf', title: 'Скрипты переписки: как поднять цену услуги' },
  'services-time-planning':  { deliveryType: 'file', fileId: '1NHhIAX86lf_OYYwmsNAWUoT4ShmXyhDx', fileName: 'services-time-planning.pdf', title: 'Планирование времени и защита от выгорания для мастера' },
  'services-targeted-ads':   { deliveryType: 'file', fileId: '1XHOlmib33j0Z0oe2i8C-hvy3w76om-KU', fileName: 'services-targeted-ads.pdf', title: 'Таргет VK Ads и Яндекс.Директ для услуг' },
  'services-word-of-mouth':  { deliveryType: 'file', fileId: '1l2UuOtlMrlm9Ol6wnnuV-UwY1wwC4miO', fileName: 'services-word-of-mouth.pdf', title: 'Сарафанное радио и система отзывов для самозанятого' },
  // Pro‑тарифы калькулятора (без файла, доступ ссылкой)
  'calc-pro-year':           { deliveryType: 'link', shareUrl: 'https://delo-delai.ru/pro-access/?plan=year', title: 'Калькулятор Pro — годовой доступ' },
  'calc-pro-lifetime':       { deliveryType: 'link', shareUrl: 'https://delo-delai.ru/pro-access/?plan=lifetime', title: 'Калькулятор Pro — пожизненный доступ' }
};

// === Извлекаем данные о платеже ===
// Поддерживаем 3 формы входных данных:
// 1) Прямо от Webhook (как у Special English): items[0].json = { body: { event, object } }
// 2) Уже извлечённое body (если родительский workflow передал $json.body): items[0].json = { event, object }
// 3) Прямо object (если родитель передал ровно тело уведомления): items[0].json = { id, status, metadata }
const raw = items[0].json || {};
const body = raw.body || raw;
const object = body.object || body;
const metadata = (object && object.metadata) || {};

// Этот receiver слушает только webhook /webhook/delaydelo-yukassa,
// он принимает только события из своего магазина ЮKassa, фильтр project не нужен.

const slug = (metadata.guide_slug || '').toString();
const email = (
  metadata.email ||
  (object.receipt && object.receipt.customer && object.receipt.customer.email) ||
  ''
).toString().trim();
const paymentId = (object.id || '').toString();
const amount = object.amount || {};

if (!slug || !MAP[slug]) {
  throw new Error('Unknown or missing guide_slug in metadata: ' + slug);
}
if (!email) {
  throw new Error('Missing email in metadata');
}

const product = MAP[slug];
const payload = {
  guide_slug: slug,
  email,
  payment_id: paymentId,
  amount_value: amount.value,
  amount_currency: amount.currency,
  delivery_type: product.deliveryType,
  title: product.title
};

if (product.deliveryType === 'file') {
  payload.fileId = product.fileId;
  payload.fileName = product.fileName;
} else {
  payload.shareUrl = product.shareUrl;
}

return [{ json: payload }];
